// Receives 5 inputs — one from each Google Sheets read node.
// Each input is a list of row items (not wrapped in .rows).
// Identify each sheet by its column names.

const all = $input.all();
let sourcing=[], candidates=[], panel=[], offers=[], pipeline=[];

for (const item of all) {
  // Google Sheets node returns rows directly as item.json
  // When aggregated they come as arrays; handle both cases
  const rows = Array.isArray(item.json) ? item.json :
               (item.json.rows ? item.json.rows : [item.json]);

  if (!rows.length || !rows[0]) continue;
  const keys = Object.keys(rows[0]).map(k=>k.toLowerCase()).join(',');

  if      (keys.includes('source_channel') || keys.includes('hire_rate') || keys.includes('screen_rate'))
    sourcing   = rows;
  else if (keys.includes('rejection_reason') || keys.includes('current_stage'))
    candidates = rows;
  else if (keys.includes('panels_conducted') || keys.includes('feedback_submission'))
    panel      = rows;
  else if (keys.includes('offer_id') || keys.includes('comp_offered') || keys.includes('decline_reason'))
    offers     = rows;
  else if (keys.includes('event_id') || keys.includes('sla_days') || keys.includes('stage_date'))
    pipeline   = rows;
}

const MAX = 80;
const clean = arr => arr.slice(0, MAX).map(r => {
  const out = {};
  for (const [k,v] of Object.entries(r))
    if (v!==null && v!==undefined && String(v).trim()!=='') out[k]=v;
  return out;
});

return [{ json: {
  sourcing_data:  clean(sourcing),
  candidate_data: clean(candidates),
  panel_data:     clean(panel),
  offer_data:     clean(offers),
  pipeline_data:  clean(pipeline),
  row_counts: {
    sourcing:   sourcing.length,
    candidates: candidates.length,
    panel:      panel.length,
    offers:     offers.length,
    pipeline:   pipeline.length,
  },
  run_id:     'RUN-' + Date.now(),
  started_at: new Date().toISOString()
}}];

