const item    = $input.first().json;
const content = item.choices || [];
const raw     = content.length ? (content[0].message?.content || '') : '';

let ev = {};
try {
  const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
  const parsed  = JSON.parse(cleaned);
  // Normalize scores: if overall_quality > 1, it's on 0-10 scale
  const oq = parsed.overall_quality || 0;
  ev = {
    overall_quality: oq,   // keep raw 0-10, Streamlit normalizes
    per_agent:       parsed.per_agent || {},
    approved:        parsed.approved !== undefined ? parsed.approved : (oq >= 6),
    flags:           parsed.flags || [],
    eval_notes:      parsed.eval_notes || parsed.notes || '',
  };
} catch(e) {
  ev = {
    overall_quality: 0,
    per_agent: {},
    approved: false,
    flags: ['parse error'],
    eval_notes: 'parse failed: ' + e.message + ' | raw: ' + raw.slice(0, 100),
  };
}

let up = {};
try { up = $('📦 Bundle Results').first().json; } catch(e) {}

return [{ json: { ...up, evaluation: ev } }];

const item   = $input.first().json;
const agents = item.agent_results || [];

// Exact model used per agent (from workflow HTTP nodes)
const AGENT_MODELS = {
  'sourcing_quality':  'gpt-4o',
  'rejection_pattern': 'gpt-4o',
  'panel_load':        'gpt-4o-mini',
  'offer_insights':    'gpt-4o',
  'pipeline_health':   'gpt-4o-mini',
};

// OpenAI pricing per 1K tokens (GPT-4o = $2.50/1M in, $10/1M out)
const COST = {
  'gpt-4o':      { i: 0.0025,  o: 0.010  },
  'gpt-4o-mini': { i: 0.00015, o: 0.0006 },
};

let total = 0, mini_total = 0;

const per = agents.map(a => {
  const agentKey = (a.agent || '').toLowerCase().replace(/ /g,'_');
  const model    = AGENT_MODELS[agentKey] || 'gpt-4o';

  // Try to get real token counts; fallback to typical estimates
  const ti = (a._tokens_in  && a._tokens_in  > 0) ? a._tokens_in  : 1200;
  const to = (a._tokens_out && a._tokens_out > 0) ? a._tokens_out : 350;

  const tc   = COST[model]          || COST['gpt-4o'];
  const mc   = COST['gpt-4o-mini'];
  const act  = (ti / 1000) * tc.i  + (to / 1000) * tc.o;
  const mact = (ti / 1000) * mc.i  + (to / 1000) * mc.o;

  total      += act;
  mini_total += mact;

  return {
    agent:       a.agent,
    model:       model,
    tokens_in:   ti,
    tokens_out:  to,
    actual_usd:  act.toFixed(5),
    mini_equiv:  mact.toFixed(5),
    tokens:      ti + to,
  };
});

return [{ json: { ...item,
  optimization: {
    per_agent_costs:   per,
    total_actual_usd:  total.toFixed(5),
    haiku_equiv_usd:   mini_total.toFixed(5),
    potential_savings: Math.max(0, total - mini_total).toFixed(5),
    tips: [
      'Panel Load + Pipeline Health use GPT-4o-mini (~94% cheaper per token)',
      'Cache repeated Pinecone RAG queries to reduce embedding costs',
      'Limit Google Sheets payload to top 50 rows for faster, cheaper runs',
    ],
  },
}}];

const inputs = $input.all();
let evData = {}, optimData = {}, base = {};

for (const inp of inputs) {
  if (inp.json.evaluation)   evData    = inp.json;
  if (inp.json.optimization) optimData = inp.json;
  if (inp.json.agent_results && !base.agent_results) base = inp.json;
}

const agents = evData.agent_results || optimData.agent_results || base.agent_results || [];
const ev     = evData.evaluation    || {};
const optim  = optimData.optimization || {};

// ── Always calculate cost inline from actual model used ──────────────────────
const AGENT_MODELS = {
  'sourcing_quality':  'gpt-4o',
  'rejection_pattern': 'gpt-4o',
  'panel_load':        'gpt-4o-mini',
  'offer_insights':    'gpt-4o',
  'pipeline_health':   'gpt-4o-mini',
};
const COST = {
  'gpt-4o':      { i: 0.0025,  o: 0.010  },
  'gpt-4o-mini': { i: 0.00015, o: 0.0006 },
};

let totalCost = 0;
let miniTotal = 0;

const perAgentCosts = agents.map(a => {
  const key   = (a.agent || '').toLowerCase().replace(/ /g,'_');
  const model = AGENT_MODELS[key] || 'gpt-4o';
  const tc    = COST[model] || COST['gpt-4o'];
  const mc    = COST['gpt-4o-mini'];
  // Use real tokens if available, else typical estimate
  const ti    = (a._tokens_in  > 0) ? a._tokens_in  : 1200;
  const to    = (a._tokens_out > 0) ? a._tokens_out : 350;
  const act   = (ti/1000)*tc.i + (to/1000)*tc.o;
  const mini  = (ti/1000)*mc.i + (to/1000)*mc.o;
  totalCost  += act;
  miniTotal  += mini;
  return {
    agent:      a.agent,
    model:      model,
    tokens_in:  ti,
    tokens_out: to,
    actual_usd: act.toFixed(5),
    mini_equiv: mini.toFixed(5),
  };
});

// Also add eval agent cost
const evalTi   = 800, evalTo = 200;
const evalCost = (evalTi/1000)*COST['gpt-4o'].i + (evalTo/1000)*COST['gpt-4o'].o;
totalCost += evalCost;
perAgentCosts.push({
  agent: 'evaluation', model: 'gpt-4o',
  tokens_in: evalTi, tokens_out: evalTo,
  actual_usd: evalCost.toFixed(5), mini_equiv: '0.00014',
});

const savings = Math.max(0, totalCost - miniTotal);

// Use optimization node data if it actually has values, else use inline calc
const finalCosts = {
  total_usd:         (optim.total_actual_usd && parseFloat(optim.total_actual_usd) > 0)
                       ? optim.total_actual_usd
                       : totalCost.toFixed(5),
  haiku_equiv_usd:   optim.haiku_equiv_usd   || miniTotal.toFixed(5),
  potential_savings: optim.potential_savings  || savings.toFixed(5),
  per_agent:         (optim.per_agent_costs && optim.per_agent_costs.length > 0)
                       ? optim.per_agent_costs
                       : perAgentCosts,
  tips: optim.tips || [
    'Panel Load + Pipeline Health use GPT-4o-mini (~94% cheaper per token)',
    'Cache repeated Pinecone RAG queries to reduce embedding costs',
    'Limit payload to top 50 rows for faster, cheaper runs',
  ],
};

return [{ json: {
  run_id:       base.run_id || evData.run_id || new Date().getTime().toString(),
  completed_at: new Date().toISOString(),
  status:       'complete',
  agents_run:   agents.length,

  insights: agents.map(a => ({
    agent:            a.agent,
    recommendation:   a.recommendation   || '',
    confidence_score: a.confidence_score || 0,
    evidence:         a.evidence         || [],
    key_findings:     a.key_findings     || {},
    alternative:      a.alternative      || '',
    _tokens_in:       a._tokens_in       || 0,
    _tokens_out:      a._tokens_out      || 0,
  })),

  evaluation: {
    overall_quality: ev.overall_quality || 0,
    approved:        ev.approved        !== undefined ? ev.approved : false,
    per_agent:       ev.per_agent       || {},
    flags:           ev.flags           || [],
    notes:           ev.eval_notes      || ev.notes || '',
  },

  cost_summary: finalCosts,

  quick_read: agents.map(a =>
    `[${(a.agent||'').toUpperCase().replace(/_/g,' ')}]\n` +
    `Recommendation: ${a.recommendation||'none'}\n` +
    `Confidence: ${((a.confidence_score||0)*100).toFixed(0)}%\n`
  ).join('\n'),
}}];

return $input.all().map(item => {
  const row = item.json;

  // --- START FIX: Convert Excel Date to Readable String ---
  if (row.Week_Start_Date && typeof row.Week_Start_Date === 'number') {
      // Excel counts days from 1900. JavaScript counts from 1970.
      // 25569 is the number of days between 1900 and 1970.
      const jsDate = new Date((row.Week_Start_Date - 25569) * 86400 * 1000);
      // Convert to "YYYY-MM-DD" format (e.g., "2022-01-03")
      row.Week_Start_Date = jsDate.toISOString().split('T')[0];
  }

  // Convert row object to readable string
  const str = Object.keys(row).map(k => `${k}: ${row[k]}`).join(", ");

  // Convert to Base64 to mimic a file
  const b64 = Buffer.from(str).toString('base64');

  return {
    json: {
      text_content: b64,
      ...row
    }
  };
});

// ═══════════════════════════════════════════════════════════════════════════
// RAG RETRIEVAL NODE
// Queries the Pinecone knowledge base BEFORE agents run.
// Uses the same indexes and credentials as the ingestion flow:
//   • "hiring"  index → RAG docs (benchmarks, policies, rubrics)
//   • "v1"      index → Excel data (candidates, pipeline, offers, etc.)
// Retrieves top-5 relevant chunks per agent and injects context
// into each agent's prompt for grounded, evidence-based outputs.
// ═══════════════════════════════════════════════════════════════════════════

const OPENAI_KEY     = $vars.OPENAI_API_KEY;
const PINECONE_KEY   = $vars.PINECONE_API_KEY;

// Index hosts — set these in n8n Variables after creating indexes
// Find in app.pinecone.io → your index → "Host" field
const HOST_DOCS  = $vars.PINECONE_HOST_DOCS  || '';   // "hiring" index host
const HOST_EXCEL = $vars.PINECONE_HOST_EXCEL || '';   // "v1" index host

const EMBED_MODEL = 'text-embedding-3-large';
const TOP_K       = 5;
const MIN_SCORE   = 0.30;

// Per-agent semantic queries — tuned to match the knowledge base content
const AGENT_QUERIES = {
  sourcing_quality:  'best sourcing channels hire rate cost per hire LinkedIn referral channel strategy benchmark performance',
  rejection_pattern: 'rejection reasons candidate drop-off JD mismatch withdrawal stage failure technical screen skills',
  panel_load:        'interviewer panel count overloaded burnout feedback rate rebalance monthly capacity thresholds',
  offer_insights:    'offer acceptance decline compensation gap comp delta competing offer signing bonus salary bands',
  pipeline_health:   'time to hire SLA breach funnel conversion bottleneck stage escalation TTF target days open roles',
};

// ── Helper: embed a text string ────────────────────────────────────────────
async function embed(text) {
  const res = await fetch('https://api.openai.com/v1/embeddings', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${OPENAI_KEY}`,
    },
    body: JSON.stringify({
      model: EMBED_MODEL,
      input: [text],
      dimensions: 1024,
    }),
  });
  const data = await res.json();
  if (!res.ok) throw new Error(`OpenAI embed error: ${JSON.stringify(data)}`);
  return data.data[0].embedding;
}

// ── Helper: query one Pinecone index ───────────────────────────────────────
async function queryPinecone(host, vector, filter, namespace) {
  if (!host) return [];   // skip if host not configured
  const body = {
    vector, topK: TOP_K, includeMetadata: true,
  };
  if (filter)    body.filter    = filter;
  if (namespace) body.namespace = namespace;

  const res = await fetch(`${host}/query`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Api-Key': PINECONE_KEY,
    },
    body: JSON.stringify(body),
  });
  const data = await res.json();
  if (!res.ok) return [];   // fail gracefully
  return (data.matches || []).filter(m => m.score >= MIN_SCORE);
}

// ── Helper: format matches into readable context string ────────────────────
function formatContext(matches, sourceLabel) {
  return matches.map(m => {
    const src  = m.metadata?.source || m.metadata?.doc_name || sourceLabel;
    const text = m.metadata?.text || m.metadata?.pageContent || '';
    return `[${src} | score:${Math.round(m.score*100)/100}]\n${text.slice(0,600)}`;
  }).join('\n\n---\n\n');
}

// ── Main: retrieve context for each agent ──────────────────────────────────
const item = $input.first().json;
const rag_context = {};

for (const [agentKey, query] of Object.entries(AGENT_QUERIES)) {
  try {
    const qVec = await embed(query);

    // Query docs KB (benchmarks, policies, rubrics)
    // Filter to agent-specific and cross-agent docs
    const docsMatches = await queryPinecone(
      HOST_DOCS, qVec,
      null,   // no filter — search all docs
      null    // no namespace on docs index
    );

    // Query Excel KB (actual hiring data already ingested)
    const excelMatches = await queryPinecone(
      HOST_EXCEL, qVec,
      null,
      'Production'
    );

    const docsCtx  = formatContext(docsMatches,  'Knowledge Base');
    const excelCtx = formatContext(excelMatches, 'Excel Data');

    // Combine both sources
    const parts = [];
    if (docsCtx.trim())  parts.push(`=== POLICY & BENCHMARK DOCUMENTS ===\n${docsCtx}`);
    if (excelCtx.trim()) parts.push(`=== HISTORICAL EXCEL DATA ===\n${excelCtx}`);

    const combined = parts.join('\n\n');
    const total    = docsMatches.length + excelMatches.length;

    rag_context[agentKey] = {
      context_text:  combined,
      chunks_found:  total,
      docs_chunks:   docsMatches.length,
      excel_chunks:  excelMatches.length,
    };

  } catch (err) {
    // Never block the pipeline — fail gracefully with empty context
    rag_context[agentKey] = {
      context_text: '',
      chunks_found: 0,
      error: err.message,
    };
  }
}

// Pass everything downstream — agents will read rag_context[agentKey].context_text
return [{ json: { ...item, rag_context } }];
